SELECT COUNT(*) FROM hm_query.report_definitions_flat

    AND LOWER(name) LIKE LOWER(CONCAT('%', #{name}, '%'))
    AND category = #{category}
    AND is_active = #{isActive}
    AND (LOWER(name) LIKE LOWER(CONCAT('%', #{q}, '%')) OR LOWER(description) LIKE LOWER(CONCAT('%', #{q}, '%')))

SELECT id, name, description, category,
       available_formats AS "availableFormats",
       is_active AS "isActive",
       created_time AS "createdTime"
FROM hm_query.report_definitions_flat

    AND LOWER(name) LIKE LOWER(CONCAT('%', #{name}, '%'))
    AND category = #{category}
    AND is_active = #{isActive}
    AND (LOWER(name) LIKE LOWER(CONCAT('%', #{q}, '%')) OR LOWER(description) LIKE LOWER(CONCAT('%', #{q}, '%')))

${orderby} ${pagination}

SELECT COUNT(*) FROM hm_query.scheduled_reports_flat

    AND report_definition_id = #{reportDefinitionId}
    AND status = #{status}
    AND frequency = #{frequency}
    AND (LOWER(report_name) LIKE LOWER(CONCAT('%', #{q}, '%')) OR LOWER(recipient_email) LIKE LOWER(CONCAT('%', #{q}, '%')))

SELECT id, report_definition_id AS "reportDefinitionId",
       report_name AS "reportName",
       format, frequency, cron_expression AS "cronExpression",
       next_run_at AS "nextRunAt", last_run_at AS "lastRunAt",
       recipient_email AS "recipientEmail",
       status, created_time AS "createdTime"
FROM hm_query.scheduled_reports_flat

    AND report_definition_id = #{reportDefinitionId}
    AND status = #{status}
    AND frequency = #{frequency}
    AND (LOWER(report_name) LIKE LOWER(CONCAT('%', #{q}, '%')) OR LOWER(recipient_email) LIKE LOWER(CONCAT('%', #{q}, '%')))

${orderby} ${pagination}

SELECT COUNT(*) FROM hm_query.report_history_flat

    AND report_definition_id = #{reportDefinitionId}
    AND status = #{status}
    AND generated_by = #{generatedBy}
    AND (LOWER(name) LIKE LOWER(CONCAT('%', #{q}, '%')) OR LOWER(report_definition_name) LIKE LOWER(CONCAT('%', #{q}, '%')))

SELECT id, report_definition_id AS "reportDefinitionId",
       report_definition_name AS "reportDefinitionName",
       name, format, generated_by AS "generatedBy",
       file_url AS "fileUrl", file_size_bytes AS "fileSizeBytes",
       record_count AS "recordCount", status,
       completed_at AS "completedAt", error_message AS "errorMessage",
       created_time AS "createdTime"
FROM hm_query.report_history_flat

    AND report_definition_id = #{reportDefinitionId}
    AND status = #{status}
    AND generated_by = #{generatedBy}
    AND (LOWER(name) LIKE LOWER(CONCAT('%', #{q}, '%')) OR LOWER(report_definition_name) LIKE LOWER(CONCAT('%', #{q}, '%')))

${orderby} ${pagination}
